export const paper = { year: 2025, name: 'GS1', set: 'A' };

export const questions = [
{no:1, text:"With reference to investments, consider the following:\nI. Bonds\nII. Hedge Funds\nIII. Stocks\nIV. Venture Capital\nHow many of the above are treated as Alternative Investment Funds (AIFs)?", A:"Only one", B:"Only two", C:"Only three", D:"All the four", ans:"B", category:"Economy", subcategory:"Financial Markets", tags:["Alternative Investment Funds","SEBI"]},
{no:2, text:"Which of the following are the sources of income for the Reserve Bank of India?\nI. Buying and selling Government bonds\nII. Buying and selling foreign currency\nIII. Pension fund management\nIV. Lending to private companies\nV. Printing and distributing currency notes\nSelect the correct answer using the code given below.", A:"I and II only", B:"II, III and IV", C:"I, III, IV and V", D:"I, II and V", ans:"A", category:"Economy", subcategory:"Banking & Monetary Policy", tags:["RBI","Monetary Policy"]},
{no:3, text:"With reference to the Government of India, consider the following information:\nOrganization — Function — Works under\nI. Directorate of Enforcement — Enforcement of the Fugitive Economic Offenders Act, 2018 — Internal Security Division-I, Ministry of Home Affairs\nII. Directorate of Revenue Intelligence — Enforces the provisions of the Customs Act, 1962 — Department of Revenue, Ministry of Finance\nIII. Directorate General of Systems and Data Management — Carries out big data analytics to assist tax officers and policy — Department of Revenue, Ministry of Finance\nIn how many of the above rows is the information correctly matched?", A:"Only one", B:"Only two", C:"All the three", D:"None", ans:"A", category:"Polity & Governance", subcategory:"Government Bodies", tags:["Enforcement Directorate","Ministry of Finance"]},
{no:4, text:"Consider the following statements:\nStatement I: The Reserve Bank of India mandates all the listed companies in India to submit a Business Responsibility and Sustainability Report (BRSR).\nStatement II: In India, a company submitting a BRSR makes disclosures in the report that are largely non-financial in nature.\nWhich of the statements given above is/are correct?", A:"I only", B:"II only", C:"Both I and II", D:"Neither I nor II", ans:"B", category:"Economy", subcategory:"Corporate Regulation", tags:["BRSR","SEBI","ESG"]},
{no:5, text:"Consider the following statements:\nStatement I: In India, income from allied agricultural activities like poultry farming and wool rearing in rural areas is exempted from any tax.\nStatement II: In India, rural agricultural land is not considered a capital asset under the provisions of the Income-tax Act, 1961.\nWhich one of the following is correct in respect of the above statements?", A:"Both Statement I and Statement II are correct and Statement II explains Statement I.", B:"Both Statement I and Statement II are correct but Statement II does not explain Statement I.", C:"Statement I is correct but Statement II is not correct.", D:"Statement I is not correct but Statement II is correct.", ans:"D", category:"Economy", subcategory:"Taxation", tags:["Income Tax","Agriculture Income"]},
{no:6, text:"Consider the following statements:\nI. India has joined the Minerals Security Partnership as a member.\nII. India is a resource-rich country in all the 30 critical minerals that it has identified.\nIII. The Parliament in 2023 amended the Mines and Minerals (Development and Regulation) Act, 1957 empowering the Central Government to exclusively auction mining leases and composite licences for certain critical minerals.\nWhich of the statements given above are correct?", A:"I and II only", B:"II and III only", C:"I and III only", D:"I, II and III", ans:"C", category:"Economy", subcategory:"Mining & Minerals", tags:["Critical Minerals","MMDR Act","Minerals Security Partnership"]},
{no:7, text:"Consider the following statements:\nStatement I: As regards returns from an investment in a company, generally, bondholders are considered to be relatively at lower risk than stockholders.\nStatement II: Bondholders are lenders to a company whereas stockholders are its owners.\nStatement III: For repayment purpose, bondholders are prioritized over stockholders by a company.\nWhich one of the following is correct in respect of the above statements?", A:"Both Statement II and Statement III are correct and both of them explain Statement I.", B:"Both Statement I and Statement II are correct and Statement I explains Statement II.", C:"Only one of the Statements II and III is correct and that explains Statement I.", D:"Neither Statement II nor Statement III is correct.", ans:"A", category:"Economy", subcategory:"Financial Markets", tags:["Bonds","Stock Market"]},
{no:8, text:"Consider the following statements:\nI. India accounts for a very large portion of all equity option contracts traded globally.\nII. India's stock market has grown rapidly in the recent past even overtaking Hong Kong's at some point of time.\nIII. There is no regulatory body either to warn small investors about the risks of options trading or to act on unregistered financial advisors in this regard.\nWhich of the statements given above are correct?", A:"I and II only", B:"II and III only", C:"I and III only", D:"I, II and III", ans:"A", category:"Economy", subcategory:"Financial Markets", tags:["Stock Market","SEBI"]},
{no:9, text:"Consider the following statements:\nStatement I: Circular economy reduces the emissions of greenhouse gases.\nStatement II: Circular economy reduces the use of raw materials as inputs.\nStatement III: Circular economy reduces wastage in the production process.\nWhich one of the following is correct in respect of the above statements?", A:"Both Statement II and Statement III are correct and both of them explain Statement I.", B:"Both Statement II and Statement III are correct but only one of them explains Statement I.", C:"Only one of the Statements II and III is correct and that explains Statement I.", D:"Neither Statement II nor Statement III is correct.", ans:"B", category:"Environment & Ecology", subcategory:"Sustainable Development", tags:["Circular Economy"]},
{no:10, text:"Consider the following statements:\nI. Capital receipts create a liability or cause a reduction in the assets of the Government.\nII. Borrowings and disinvestment are capital receipts.\nIII. Interest received on loans creates a liability of the Government.\nWhich of the statements given above are correct?", A:"I and II only", B:"II and III only", C:"I and III only", D:"I, II and III", ans:"A", category:"Economy", subcategory:"Public Finance", tags:["Budget","Capital Receipts"]},
{no:11, text:"Consider the following statements about Raja Ram Mohan Roy:\nI. He possessed great love and respect for the traditional philosophical systems of the East.\nII. He desired his countrymen to accept the rational and scientific approach and the principle of human dignity and social equality of all men and women.\nWhich of the statements given above is/are correct?", A:"I only", B:"II only", C:"Both I and II", D:"Neither I nor II", ans:"C", category:"History", subcategory:"Modern India", tags:["Raja Ram Mohan Roy","Reform Movements"]},
{no:12, text:"Consider the following subjects with regard to the Non-Cooperation Programme:\nI. Boycott of law courts and foreign cloth\nII. Observance of strict non-violence\nIII. Retention of titles and honours without using them in public\nIV. Establishment of Panchayats for settling disputes\nHow many of the above were parts of the Non-Cooperation Programme?", A:"Only one", B:"Only two", C:"Only three", D:"All the four", ans:"C", category:"History", subcategory:"Modern India", tags:["Non-Cooperation Movement"]},
{no:13, text:"The irrigation device called 'Araghatta' was", A:"A water bag made of leather pulled over a pulley", B:"A large wheel with earthen pots tied to the outer ends of its spokes", C:"A large earthen pot driven by bullocks", D:"A large water bucket pulled up by rope directly by hand", ans:"B", category:"History", subcategory:"Ancient India", tags:["Ancient Technology","Irrigation"]},
{no:14, text:"Who among the following rulers in ancient India had assumed the titles 'Mattavilasa', 'Vichitrachitta' and 'Gunabhara'?", A:"Mahendravarman I", B:"Simhavishnu", C:"Narasimhavarman I", D:"Simhavarman", ans:"A", category:"History", subcategory:"Ancient India", tags:["Pallavas"]},
{no:15, text:"Fa-hien (Faxian), the Chinese pilgrim, travelled to India during the reign of", A:"Samudragupta", B:"Chandragupta II", C:"Kumaragupta I", D:"Skandagupta", ans:"B", category:"History", subcategory:"Ancient India", tags:["Gupta Empire","Chinese Travellers"]},
{no:16, text:"Who among the following led a successful military campaign against the kingdom of Srivijaya, the powerful maritime State, which ruled the Malay Peninsula, Sumatra, Java and the neighbouring islands?", A:"Amoghavarsha (Rashtrakuta)", B:"Prataparudra (Kakatiya)", C:"Rajendra I (Chola)", D:"Vishnuvardhana (Hoysala)", ans:"C", category:"History", subcategory:"Medieval India", tags:["Chola Empire","Srivijaya"]},
{no:17, text:"With reference to ancient India (600–322 BC), consider the following pairs:\nTerritorial Region — River flowing in the region\nI. Asmaka — Godavari\nII. Kamboja — Vipas\nIII. Avanti — Mahanadi\nIV. Kosala — Sarayu\nHow many of the pairs given above are correctly matched?", A:"Only one", B:"Only two", C:"Only three", D:"All the four", ans:"B", category:"History", subcategory:"Ancient India", tags:["Ancient Geography","Mahajanapadas"]},
{no:18, text:"The first Gandharva Mahavidyalaya, a music training school, was set up in 1901 by Vishnu Digambar Paluskar in", A:"Delhi", B:"Gwalior", C:"Ujjain", D:"Lahore", ans:"D", category:"Art & Culture", subcategory:"Music", tags:["Indian Classical Music"]},
{no:19, text:"Ashokan inscriptions suggest that the 'Pradeshika', 'Rajuka' and 'Yukta' were important officers at the", A:"Village-level administration", B:"District-level administration", C:"Provincial administration", D:"Level of the central administration", ans:"B", category:"History", subcategory:"Ancient India", tags:["Mauryan Administration","Ashoka"]},
{no:20, text:"Consider the following statements in respect of the Non-Cooperation Movement:\nI. The Congress declared the attainment of 'Swaraj' by all legitimate and peaceful means to be its objective.\nII. It was to be implemented in stages with civil disobedience and non-payment of taxes for the next stage only if 'Swaraj' did not come within a year and the Government resorted to repression.\nWhich of the statements given above is/are correct?", A:"I only", B:"II only", C:"Both I and II", D:"Neither I nor II", ans:"C", category:"History", subcategory:"Modern India", tags:["Non-Cooperation Movement"]},
{no:21, text:"Consider the following countries:\nI. Austria\nII. Bulgaria\nIII. Croatia\nIV. Serbia\nV. Sweden\nVI. North Macedonia\nHow many of the above are members of the North Atlantic Treaty Organization (NATO)?", A:"Only three", B:"Only four", C:"Only five", D:"All the six", ans:"B", category:"International Relations", subcategory:"Organizations", tags:["NATO"]},
{no:22, text:"Consider the following countries:\nI. Bolivia\nII. Brazil\nIII. Colombia\nIV. Ecuador\nV. Paraguay\nVI. Venezuela\nAndes Mountains pass through how many of the above countries?", A:"Only two", B:"Only three", C:"Only four", D:"Only five", ans:"C", category:"Geography", subcategory:"Physical Geography", tags:["Andes","World Geography"]},
{no:23, text:"Consider the following water bodies:\nI. Lake Tanganyika\nII. Lake Tonlé Sap\nIII. Patos Lagoon\nThrough how many of them does the equator pass?", A:"Only one", B:"Only two", C:"All the three", D:"None", ans:"D", category:"Geography", subcategory:"Physical Geography", tags:["Equator","Lakes"]},
{no:24, text:"Consider the following statements about turmeric during the year 2022–23:\nI. India is the largest producer and exporter of turmeric in the world.\nII. More than 30 varieties of turmeric are grown in India.\nIII. Maharashtra, Telangana, Karnataka and Tamil Nadu are major turmeric-producing States in India.\nWhich of the statements given above are correct?", A:"I and II only", B:"II and III only", C:"I and III only", D:"I, II and III", ans:"C", category:"Geography", subcategory:"Economic Geography", tags:["Agriculture","Turmeric","India Geography"]},
{no:25, text:"Which of the following are the evidences of the phenomenon of continental drift?\nI. The belt of ancient rocks from Brazil coast matches with those from Western Africa.\nII. The gold deposits of Ghana are derived from the Brazil plateau when the two continents lay side by side.\nIII. The Gondwana system of sediments from India is known to have its counterparts in six different landmasses of the Southern Hemisphere.\nSelect the correct answer using the code given below.", A:"I and III only", B:"I and II only", C:"I, II and III", D:"II and III only", ans:"C", category:"Geography", subcategory:"Physical Geography", tags:["Continental Drift","Plate Tectonics"]},
{no:26, text:"Consider the following statements:\nStatement I: The amount of dust particles in the atmosphere is more in subtropical and temperate areas than in equatorial and polar regions.\nStatement II: Subtropical and temperate areas have less dry winds.\nWhich one of the following is correct in respect of the above statements?", A:"Both Statement I and Statement II are correct and Statement II explains Statement I.", B:"Both Statement I and Statement II are correct but Statement II does not explain Statement I.", C:"Statement I is correct but Statement II is not correct.", D:"Statement I is not correct but Statement II is correct.", ans:"C", category:"Geography", subcategory:"Physical Geography", tags:["Atmosphere","Climatology"]},
{no:27, text:"Consider the following statements:\nStatement I: In January, in the Northern Hemisphere, the isotherms bend equatorward while crossing the landmasses, and poleward while crossing the oceans.\nStatement II: In January, the air over the oceans is warmer than that over the landmasses in the Northern Hemisphere.\nWhich one of the following is correct in respect of the above statements?", A:"Both Statement I and Statement II are correct and Statement II explains Statement I.", B:"Both Statement I and Statement II are correct but Statement II does not explain Statement I.", C:"Statement I is correct but Statement II is not correct.", D:"Statement I is not correct but Statement II is correct.", ans:"A", category:"Geography", subcategory:"Physical Geography", tags:["Isotherms","Climatology"]},
{no:28, text:"Consider the following statements:\nStatement I: In the context of effect of water on rocks, chalk is known as a very permeable rock whereas clay is known as quite an impermeable or least permeable rock.\nStatement II: Chalk is porous and hence can absorb water.\nStatement III: Clay is not at all porous.\nWhich one of the following is correct in respect of the above statements?", A:"Both Statement II and Statement III are correct and both of them explain Statement I.", B:"Both Statement II and Statement III are correct but only one of them explains Statement I.", C:"Only one of the Statements II and III is correct and that explains Statement I.", D:"Neither Statement II nor Statement III is correct.", ans:"C", category:"Geography", subcategory:"Physical Geography", tags:["Rocks","Geomorphology"]},
{no:29, text:"Consider the following statements:\nI. Without the atmosphere, temperature would be well below the freezing point everywhere on the Earth's surface.\nII. Heat absorbed and trapped by the atmosphere maintains our planet's average temperature.\nIII. Atmospheric gases, like carbon dioxide, are particularly good at absorbing and trapping radiation.\nWhich of the statements given above are correct?", A:"I and III only", B:"I and II only", C:"I, II and III", D:"II and III only", ans:"C", category:"Environment & Ecology", subcategory:"Climate Change", tags:["Greenhouse Effect","Climate Change"]},
{no:30, text:"Consider the following statements about the Rashtriya Gokul Mission:\nI. It is important for the upliftment of the rural poor as majority of low producing indigenous animals are with small and marginal farmers and landless labourers.\nII. It was initiated to promote indigenous cattle and buffalo rearing and conservation in a scientific and holistic manner.\nWhich of the statements given above is/are correct?", A:"I only", B:"II only", C:"Both I and II", D:"Neither I nor II", ans:"B", category:"Economy", subcategory:"Agriculture & Allied", tags:["Rashtriya Gokul Mission","Livestock"]},
{no:31, text:"Consider the following statements:\nStatement I: Studies indicate that carbon dioxide emissions from the cement industry account for more than 5% of global carbon emissions.\nStatement II: Silica-bearing clay is mixed with limestone while manufacturing cement.\nStatement III: Limestone is converted into lime during clinker production for cement manufacturing.\nWhich one of the following is correct in respect of the above statements?", A:"Both Statement II and Statement III are correct and both of them explain Statement I.", B:"Both Statement II and Statement III are correct but only one of them explains Statement I.", C:"Only one of the Statements II and III is correct and that explains Statement I.", D:"Neither Statement II nor Statement III is correct.", ans:"B", category:"Environment & Ecology", subcategory:"Climate Change", tags:["Cement Industry","Carbon Emissions"]},
{no:32, text:"Consider the following statements:\nStatement I: At the 28th United Nations Climate Change Conference (COP28), India refrained from signing the Declaration on Climate and Health.\nStatement II: The COP28 Declaration on Climate and Health is a binding declaration; and if signed, it becomes mandatory to decarbonize the health sector.\nStatement III: If India's health sector is decarbonized, the resilience of its healthcare system may be compromised.\nWhich one of the following is correct in respect of the above statements?", A:"Both Statement II and Statement III are correct and both of them explain Statement I.", B:"Both Statement II and Statement III are correct but only one of them explains Statement I.", C:"Only one of the Statements II and III is correct and that explains Statement I.", D:"Neither Statement II nor Statement III is correct.", ans:"D", category:"Environment & Ecology", subcategory:"Climate Change", tags:["COP28","Climate Change"]},
{no:33, text:"Consider the following statements:\nStatement I: Scientific studies suggest that a shift is taking place in the Earth's rotation axis.\nStatement II: Solar flares and associated coronal mass ejections bombarded the Earth's outermost atmosphere with tremendous amount of energy.\nStatement III: As the Earth's polar ice melts, the water tends to move towards the equator.\nWhich one of the following is correct in respect of the above statements?", A:"Both Statement II and Statement III are correct and both of them explain Statement I.", B:"Both Statement II and Statement III are correct but only one of them explains Statement I.", C:"Only one of the Statements II and III is correct and that explains Statement I.", D:"Neither Statement II nor Statement III is correct.", ans:"B", category:"Geography", subcategory:"Physical Geography", tags:["Earth's Axis","Geophysics"]},
{no:34, text:"Consider the following statements:\nStatement I: Article 6 of the Paris Agreement on climate change is frequently discussed in global discussions on sustainable development and climate change.\nStatement II: Article 6 of the Paris Agreement on climate change sets out the principles of carbon markets.\nStatement III: Article 6 of the Paris Agreement on climate change intends to promote inter-country non-market strategies to reach their climate targets.\nWhich one of the following is correct in respect of the above statements?", A:"Both Statement II and Statement III are correct and both of them explain Statement I.", B:"Both Statement II and Statement III are correct but only one of them explains Statement I.", C:"Only one of the Statements II and III is correct and that explains Statement I.", D:"Neither Statement II nor Statement III is correct.", ans:"C", category:"Environment & Ecology", subcategory:"Climate Change", tags:["Paris Agreement","Carbon Markets"]},
{no:35, text:"Which one of the following launched the 'Nature Solutions Finance Hub for Asia and the Pacific'?", A:"The Asian Development Bank (ADB)", B:"The Asian Infrastructure Investment Bank (AIIB)", C:"The New Development Bank (NDB)", D:"The International Bank for Reconstruction and Development (IBRD)", ans:"A", category:"Environment & Ecology", subcategory:"International Environmental Bodies", tags:["ADB","Nature Finance"]},
{no:36, text:"With reference to 'Direct Air Capture', an emerging technology, which of the following statements is/are correct?\nI. It can be used as a way of carbon sequestration.\nII. It can be a valuable approach for plastic production and in food processing.\nIII. In aviation, it can be a source of carbon for combining with hydrogen to create synthetic low-carbon fuel.\nSelect the correct answer using the code given below.", A:"I and II only", B:"III only", C:"I, II and III", D:"None of the above statements is correct.", ans:"C", category:"Science & Technology", subcategory:"Environmental Technology", tags:["Direct Air Capture","Carbon Capture"]},
{no:37, text:"Regarding Peacock tarantula (Gooty tarantula), consider the following statements:\nI. It is an omnivorous crustacean.\nII. Its natural habitat in India is only limited to some forest areas.\nIII. In its natural habitat, it is an arboreal species.\nWhich of the statements given above is/are correct?", A:"I only", B:"I and III", C:"II only", D:"II and III", ans:"D", category:"Environment & Ecology", subcategory:"Biodiversity", tags:["Gooty Tarantula","Species in News"]},
{no:38, text:"Consider the following statements:\nI. Carbon dioxide (CO₂) emissions in India are less than 0.5 t CO₂/capita.\nII. In terms of CO₂ emissions from fuel combustion, India ranks second in the Asia-Pacific region.\nIII. Electricity and heat producers are the largest sources of CO₂ emissions in India.\nWhich of the statements given above is/are correct?", A:"I and III only", B:"II only", C:"II and III only", D:"I, II and III", ans:"C", category:"Environment & Ecology", subcategory:"Climate Change", tags:["Carbon Emissions","India"]},
{no:39, text:"Consider the following pairs:\nPlant — Description\nI. Cassava — Woody shrub\nII. Ginger — Herb with pseudostem\nIII. Malabar spinach — Herbaceous climber\nIV. Mint — Annual shrub\nV. Papaya — Woody shrub\nHow many of the above pairs are correctly matched?", A:"Only two", B:"Only three", C:"Only four", D:"All the five", ans:"B", category:"Environment & Ecology", subcategory:"Biodiversity", tags:["Plants","Botany"]},
{no:40, text:"With reference to the planet Earth, consider the following statements:\nI. Rain forests produce more oxygen than that produced by oceans.\nII. Marine phytoplankton and photosynthetic bacteria produce about 50% of the world's oxygen.\nIII. Well-oxygenated surface water contains several folds higher oxygen than that in atmospheric air.\nWhich of the statements given above is/are correct?", A:"I and II", B:"II only", C:"I and III", D:"None of the above statements is correct.", ans:"B", category:"Environment & Ecology", subcategory:"Biodiversity", tags:["Oxygen","Marine Ecology"]},
{no:41, text:"Consider the following types of vehicles:\nI. Full battery electric vehicles\nII. Hydrogen fuel cell vehicles\nIII. Fuel cell-electric hybrid vehicles\nHow many of the above are considered as alternative powertrain vehicles?", A:"Only one", B:"Only two", C:"All the three", D:"None", ans:"C", category:"Science & Technology", subcategory:"Automobile Technology", tags:["Electric Vehicles","Alternative Fuel Vehicles"]},
{no:42, text:"With reference to Unmanned Aerial Vehicles (UAVs), consider the following statements:\nI. All types of UAVs can do vertical landing.\nII. All types of UAVs can do automated hovering.\nIII. All types of UAVs can use battery only as a source of power supply.\nHow many of the statements given above are correct?", A:"Only one", B:"Only two", C:"All the three", D:"None", ans:"A", category:"Science & Technology", subcategory:"Defence Technology", tags:["UAV","Drones"]},
{no:43, text:"In the context of electric vehicle batteries, consider the following elements:\nI. Cobalt\nII. Graphite\nIII. Lithium\nIV. Nickel\nHow many of the above usually make up battery cathodes?", A:"Only one", B:"Only two", C:"Only three", D:"All the four", ans:"B", category:"Science & Technology", subcategory:"Energy Storage", tags:["Electric Vehicle Batteries","Critical Minerals"]},
{no:44, text:"Consider the following:\nI. Cigarette butts\nII. Eyeglass lenses\nIII. Car tyres\nHow many of them contain plastic?", A:"Only one", B:"Only two", C:"All the three", D:"None", ans:"C", category:"Environment & Ecology", subcategory:"Pollution", tags:["Plastic Pollution"]},
{no:45, text:"Consider the following substances:\nI. Ethanol\nII. Nitroglycerine\nIII. Urea\nCoal gasification technology can be used in the production of how many of them?", A:"Only one", B:"Only two", C:"All the three", D:"None", ans:"B", category:"Science & Technology", subcategory:"Chemistry & Energy", tags:["Coal Gasification"]},
{no:46, text:"What is the common characteristic of the chemical substances generally known as CL-20, HMX and LLM-105, which are sometimes talked about in media?", A:"These are alternatives to hydrofluorocarbon refrigerants.", B:"These are explosives in military weapons.", C:"These are high-energy fuels for cruise missiles.", D:"These are fuels for rocket propulsion.", ans:"B", category:"Science & Technology", subcategory:"Defence Technology", tags:["Explosives","Defence Chemistry"]},
{no:47, text:"Consider the following statements:\nI. It is expected that Majorana 1 chip will enable quantum computing.\nII. Majorana 1 chip has been introduced by Amazon Web Services (AWS).\nIII. Deep learning is a subset of machine learning.\nWhich of the statements given above are correct?", A:"I and II only", B:"II and III only", C:"I and III only", D:"I, II and III", ans:"C", category:"Science & Technology", subcategory:"IT & Computers", tags:["Quantum Computing","Majorana 1","Artificial Intelligence"]},
{no:48, text:"With reference to monoclonal antibodies, often mentioned in news, consider the following statements:\nI. They are man-made proteins.\nII. They stimulate immunological functions due to their ability to bind to specific antigens.\nIII. They are used in treating viral infections like that of Nipah virus.\nWhich of the statements given above are correct?", A:"I and II only", B:"II and III only", C:"I and III only", D:"I, II and III", ans:"D", category:"Science & Technology", subcategory:"Biotechnology", tags:["Monoclonal Antibodies","Biotechnology"]},
{no:49, text:"Consider the following statements:\nI. No virus can survive in ocean waters.\nII. No virus can infect bacteria.\nIII. No virus can change the cellular transcriptional activity in host cells.\nHow many of the statements given above are correct?", A:"Only one", B:"Only two", C:"All the three", D:"None", ans:"D", category:"Science & Technology", subcategory:"Biology", tags:["Virology"]},
{no:50, text:"Consider the following statements:\nStatement I: Activated carbon is a good and attractive tool to remove pollutants from effluent streams and to remediate contaminants from various industries.\nStatement II: Activated carbon exhibits a large surface area and a strong potential for adsorbing heavy metals.\nStatement III: Activated carbon can be easily synthesized from environmental wastes with high carbon content.\nWhich one of the following is correct in respect of the above statements?", A:"Both Statement II and Statement III are correct and both of them explain Statement I.", B:"Both Statement II and Statement III are correct but only one of them explains Statement I.", C:"Only one of the Statements II and III is correct and that explains Statement I.", D:"Neither Statement II nor Statement III is correct.", ans:"A", category:"Science & Technology", subcategory:"Chemistry & Energy", tags:["Activated Carbon","Pollution Control"]},
{no:51, text:"With reference to the Indian polity, consider the following statements:\nI. An Ordinance can amend any Central Act.\nII. An Ordinance can abridge a Fundamental Right.\nIII. An Ordinance can come into effect from a back date.\nWhich of the statements given above are correct?", A:"I and II only", B:"II and III only", C:"I and III only", D:"I, II and III", ans:"C", category:"Polity & Governance", subcategory:"Executive & Legislative Powers", tags:["Ordinance","Article 123"]},
{no:52, text:"Consider the following pairs:\nState — Description\nI. Arunachal Pradesh — The capital is named after a fort, and the State has two National Parks\nII. Nagaland — The State came into existence on the basis of a Constitutional Amendment Act\nIII. Tripura — Initially a Part 'C' State, became a centrally administered territory in 1956 and later attained statehood\nHow many of the above pairs are correctly matched?", A:"Only one", B:"Only two", C:"All the three", D:"None", ans:"A", category:"Polity & Governance", subcategory:"States Reorganization", tags:["States Reorganization","North East India"]},
{no:53, text:"With reference to India, consider the following:\nI. The Inter-State Council\nII. The National Security Council\nIII. Zonal Councils\nHow many of the above were established as per the provisions of the Constitution of India?", A:"Only one", B:"Only two", C:"All the three", D:"None", ans:"D", category:"Polity & Governance", subcategory:"Centre-State Relations", tags:["Inter-State Council","Zonal Councils"]},
{no:54, text:"Consider the following statements:\nI. The Constitution of India explicitly mentions that in certain spheres the Governor of a State acts in his/her own discretion.\nII. The President of India can, of his/her own, reserve a bill passed by a State Legislature for his/her consideration without it being forwarded by the Governor of the State concerned.\nWhich of the statements given above is/are correct?", A:"I only", B:"II only", C:"Both I and II", D:"Neither I nor II", ans:"A", category:"Polity & Governance", subcategory:"Governor", tags:["Governor","State Executive"]},
{no:55, text:"Consider the following pairs:\nProvision in the Constitution of India — Stated under\nI. Separation of Judiciary from the Executive in the public services of the State — Directive Principles of State Policy\nII. Valuing and preserving the rich heritage of our composite culture — Fundamental Duties\nIII. Prohibition of employment of children below the age of 14 years in factories — Fundamental Rights\nHow many of the above pairs are correctly matched?", A:"Only one", B:"Only two", C:"All the three", D:"None", ans:"B", category:"Polity & Governance", subcategory:"Constitution", tags:["Fundamental Rights","DPSP","Fundamental Duties"]},
{no:56, text:"Consider the following statements:\nWith reference to the Constitution of India, if an area in a State is declared as a Scheduled Area under the Fifth Schedule:\nI. The State Government loses its executive power in such areas and a local body assumes total administration.\nII. The Union Government can take over the total administration of such areas under certain circumstances on the recommendations of the Governor.\nWhich of the statements given above is/are correct?", A:"I only", B:"II only", C:"Both I and II", D:"Neither I nor II", ans:"D", category:"Polity & Governance", subcategory:"Constitution", tags:["Fifth Schedule","Scheduled Areas"]},
{no:57, text:"With reference to India, consider the following pairs:\nOrganization — Union Ministry\nI. The National Automotive Board — Ministry of Commerce and Industry\nII. The Coir Board — Ministry of Heavy Industries\nIII. The National Centre for Trade Information — Ministry of Micro, Small and Medium Enterprises\nHow many of the above pairs are correctly matched?", A:"Only one", B:"Only two", C:"All the three", D:"None", ans:"A", category:"Polity & Governance", subcategory:"Government Bodies", tags:["Statutory Bodies","Ministries"]},
{no:58, text:"Consider the following subjects under the Constitution of India:\nI. List I (Union List) in the Seventh Schedule\nII. Extent of the executive power of a State\nIII. Conditions of the Governor's office\nFor a constitutional amendment with respect to which of the above, ratification by the Legislatures of not less than one-half of the States is required before presenting the Bill to the President of India for assent?", A:"I and II only", B:"II and III only", C:"I and III only", D:"I, II and III", ans:"A", category:"Polity & Governance", subcategory:"Constitutional Amendment", tags:["Article 368","Constitutional Amendment"]},
{no:59, text:"With reference to the Indian polity, consider the following statements:\nI. The Governor of a State is not answerable to any court for the exercise and performance of the powers and duties of his/her office.\nII. No criminal proceedings shall be instituted or continued against the Governor during his/her term of office.\nIII. Members of a State Legislature are not liable to any proceedings in any court in respect of anything said within the House.\nWhich of the statements given above are correct?", A:"I and II only", B:"II and III only", C:"I and III only", D:"I, II and III", ans:"D", category:"Polity & Governance", subcategory:"Governor", tags:["Governor Immunity","Parliamentary Privilege"]},
{no:60, text:"Consider the following activities:\nI. Production of crude oil\nII. Refining, storage and distribution of petroleum\nIII. Marketing and sale of petroleum products\nIV. Production of natural gas\nHow many of the above activities are regulated by the Petroleum and Natural Gas Regulatory Board (PNGRB) in India?", A:"Only one", B:"Only two", C:"Only three", D:"All the four", ans:"B", category:"Economy", subcategory:"Energy Sector Regulation", tags:["PNGRB","Petroleum"]},
{no:61, text:"Suppose the revenue expenditure is ₹80,000 crores and the revenue receipts of the Government are ₹60,000 crores. The Government budget also shows borrowings of ₹10,000 crores and interest payments of ₹6,000 crores. Which of the following statements are correct?\nI. Revenue deficit is ₹20,000 crores.\nII. Fiscal deficit is ₹10,000 crores.\nIII. Primary deficit is ₹4,000 crores.", A:"I and II only", B:"II and III only", C:"I and III only", D:"I, II and III", ans:"C", category:"Economy", subcategory:"Public Finance", tags:["Fiscal Deficit","Budget"]},
{no:62, text:"India is one of the founding members of the International North-South Transport Corridor (INSTC), a multimodal transportation corridor, which will connect", A:"India to Central Asia to Europe via Iran", B:"India to Central Asia via China", C:"India to South-East Asia through Bangladesh and Myanmar", D:"India to Europe through Azerbaijan", ans:"A", category:"International Relations", subcategory:"Connectivity Projects", tags:["INSTC","Connectivity"]},
{no:63, text:"Consider the following statements:\nStatement I: Of the two major ethanol producers in the world, Brazil and the USA, Brazil produces more ethanol than the USA.\nStatement II: Unlike the USA where corn is the principal feedstock, sugarcane is the principal feedstock for ethanol production in Brazil.", A:"Both I and II are correct and II explains I.", B:"Both I and II are correct but II does not explain I.", C:"I is not correct but II is correct.", D:"I is correct but II is not correct.", ans:"C", category:"Economy", subcategory:"Agriculture & Allied", tags:["Ethanol","Biofuel"]},
{no:64, text:"The World Bank warned that India could become one of the first places where wet-bulb temperatures routinely exceed 35°C. Which statements best reflect this implication?\nI. Peninsular India will most likely suffer from flooding, tropical cyclones and droughts.\nII. The survival of animals including humans will be affected as shedding of body heat through perspiration becomes difficult.", A:"I only", B:"II only", C:"Both I and II", D:"Neither I nor II", ans:"B", category:"Environment & Ecology", subcategory:"Climate Change", tags:["Wet-bulb Temperature","Climate Change"]},
{no:65, text:"A country's fiscal deficit stands at ₹50,000 crores. It receives ₹10,000 crores through non-debt creating capital receipts. The country's interest liabilities are ₹1,500 crores. What is the gross primary deficit?", A:"₹48,500 crores", B:"₹51,500 crores", C:"₹58,500 crores", D:"None of the above", ans:"A", category:"Economy", subcategory:"Public Finance", tags:["Primary Deficit","Budget"]},
{no:66, text:"Which of the following statements with regard to recommendations of the 15th Finance Commission are correct?\nI. Recommended ₹4,800 crores (2022–23 to 2025–26) to improve educational outcomes.\nII. 45% of the net proceeds of Union taxes are to be shared with States.\nIII. ₹45,000 crores as performance-based incentive for agricultural reforms.\nIV. Reintroduced tax effort criterion to reward fiscal performance.", A:"I, II and III", B:"I, II and IV", C:"I, III and IV", D:"II, III and IV", ans:"C", category:"Economy", subcategory:"Public Finance", tags:["15th Finance Commission","Fiscal Federalism"]},
{no:67, text:"Consider the following statements regarding the International Bank for Reconstruction and Development (IBRD):\nI. Provides loans and guarantees to middle-income countries.\nII. Works single-handedly to help developing countries reduce poverty.\nIII. Established to help Europe rebuild after World War II.", A:"I and II only", B:"II and III only", C:"I and III only", D:"I, II and III", ans:"C", category:"Economy", subcategory:"International Financial Institutions", tags:["IBRD","World Bank"]},
{no:68, text:"Consider the following statements regarding RTGS and NEFT:\nI. RTGS settlement is instantaneous while NEFT takes some time.\nII. RTGS charges customers for inward transactions while NEFT does not.\nIII. RTGS operating hours are restricted on certain days whereas NEFT is not.", A:"I only", B:"I and II", C:"I and III", D:"III only", ans:"A", category:"Economy", subcategory:"Banking", tags:["RTGS","NEFT","Payment Systems"]},
{no:69, text:"Consider the following countries:\nI. United Arab Emirates\nII. France\nIII. Germany\nIV. Singapore\nV. Bangladesh\nHow many countries among the above accept international merchant payments under UPI?", A:"Only two", B:"Only three", C:"Only four", D:"All the five", ans:"D", category:"Economy", subcategory:"Banking", tags:["UPI","Digital Payments"]},
{no:70, text:"Consider the following statements about PM Surya Ghar Muft Bijli Yojana:\nI. Targets installation of one crore rooftop solar systems.\nII. MNRE provides training for installation, maintenance and repair.\nIII. Aims to create more than three lakh skilled manpower.", A:"I and II only", B:"I and III only", C:"II and III only", D:"I, II and III", ans:"D", category:"Economy", subcategory:"Government Schemes", tags:["PM Surya Ghar","Solar Energy"]},
{no:71, text:"\"Sedition has become my religion\" was the famous statement made by Gandhiji at the time of", A:"Champaran Satyagraha", B:"Publicly violating Salt Law at Dandi", C:"Attending the Second Round Table Conference in London", D:"Launch of the Quit India Movement", ans:"B", category:"History", subcategory:"Modern India", tags:["Dandi March","Salt Satyagraha"]},
{no:72, text:"The famous female figurine known as the 'Dancing Girl', found at Mohenjo-daro, is made of", A:"Carnelian", B:"Clay", C:"Bronze", D:"Gold", ans:"C", category:"History", subcategory:"Ancient India", tags:["Indus Valley Civilization","Mohenjo-daro"]},
{no:73, text:"Who provided legal defence to the people arrested in the aftermath of the Chauri Chaura incident?", A:"C. R. Das", B:"Madan Mohan Malaviya and Krishna Kant", C:"Dr. Saifuddin Kitchlew and Khwaja Hasan Nizami", D:"M. A. Jinnah", ans:"B", category:"History", subcategory:"Modern India", tags:["Chauri Chaura","Freedom Struggle"]},
{no:74, text:"Subsequent to which event did Gandhiji include the upliftment of 'Harijans' in his political and social programme?", A:"The Poona Pact", B:"Gandhi-Irwin Agreement", C:"Arrest of Congress leadership during Quit India Movement", D:"Government of India Act, 1935", ans:"A", category:"History", subcategory:"Modern India", tags:["Poona Pact","Gandhi"]},
{no:75, text:"Consider the following fruits:\nI. Papaya\nII. Pineapple\nIII. Guava\nHow many of the above were introduced into India by the Portuguese during the 16th–17th centuries?", A:"Only one", B:"Only two", C:"All the three", D:"None", ans:"C", category:"History", subcategory:"Medieval India", tags:["Portuguese in India","Crop History"]},
{no:76, text:"Consider the following countries:\nI. United Kingdom\nII. Denmark\nIII. New Zealand\nIV. Australia\nV. Brazil\nHow many of the above countries have more than four time zones?", A:"All the five", B:"Only four", C:"Only three", D:"Only two", ans:"C", category:"Geography", subcategory:"Physical Geography", tags:["Time Zones","World Geography"]},
{no:77, text:"Consider the following statements:\nI. Anadyr (Siberia) and Nome (Alaska) are only a few kilometres apart but are on different calendar days.\nII. When it is Monday in Anadyr, it is Tuesday in Nome.", A:"I only", B:"II only", C:"Both I and II", D:"Neither I nor II", ans:"A", category:"Geography", subcategory:"Physical Geography", tags:["International Date Line"]},
{no:78, text:"Who among the following was the founder of the 'Self-Respect Movement'?", A:"Periyar E. V. Ramasamy Naicker", B:"Dr. B. R. Ambedkar", C:"Bhaskarrao Jadhav", D:"Dinkarrao Javalkar", ans:"A", category:"History", subcategory:"Modern India", tags:["Self-Respect Movement","Periyar"]},
{no:79, text:"Consider the following pairs:\nCountry — Resource-rich in\nI. Botswana — Diamond\nII. Chile — Lithium\nIII. Indonesia — Nickel\nHow many of the above rows are correctly matched?", A:"Only one", B:"Only two", C:"All the three", D:"None", ans:"C", category:"Geography", subcategory:"Economic Geography", tags:["Mineral Resources","World Geography"]},
{no:80, text:"Consider the following pairs:\nRegion — Country\nI. Mallorca — Italy\nII. Normandy — Spain\nIII. Sardinia — France\nHow many of the above rows are correctly matched?", A:"Only one", B:"Only two", C:"All the three", D:"None", ans:"D", category:"Geography", subcategory:"Physical Geography", tags:["World Geography","Regions"]},
{no:81, text:"Consider the following statements:\nStatement I: Some rare earth elements are used in the manufacture of flat television screens and computer monitors.\nStatement II: Some rare earth elements have phosphorescent properties.\nWhich one of the following is correct?", A:"Both Statement I and Statement II are correct and Statement II explains Statement I.", B:"Both Statement I and Statement II are correct but Statement II does not explain Statement I.", C:"Statement I is correct but Statement II is not correct.", D:"Statement I is not correct but Statement II is correct.", ans:"A", category:"Science & Technology", subcategory:"Materials Science", tags:["Rare Earth Elements"]},
{no:82, text:"Consider the following statements:\nI. Indian Railways prepared a National Rail Plan (NRP) for a future-ready railway system by 2028.\nII. Kavach is an Automatic Train Protection system developed in collaboration with Germany.\nIII. Kavach consists of RFID tags fitted on tracks in station sections.\nWhich of the above statements are not correct?", A:"I and II only", B:"II and III only", C:"I and III only", D:"I, II and III", ans:"A", category:"Science & Technology", subcategory:"Transport Technology", tags:["Kavach","Indian Railways"]},
{no:83, text:"Consider the following space missions:\nI. Axiom-4\nII. SpaDeX\nIII. Gaganyaan\nHow many of the above encourage and support microgravity research?", A:"Only one", B:"Only two", C:"All the three", D:"None", ans:"B", category:"Science & Technology", subcategory:"Space", tags:["ISRO","Space Missions","Gaganyaan"]},
{no:84, text:"Consider the following pairs:\nAircraft — Description\nI. Dornier-228 — Maritime patrol aircraft\nII. IL-76 — Supersonic combat aircraft\nIII. C-17 Globemaster III — Military transport aircraft\nHow many pairs are correctly matched?", A:"Only one", B:"Only two", C:"All the three", D:"None", ans:"B", category:"Science & Technology", subcategory:"Defence Technology", tags:["Military Aircraft","Defence"]},
{no:85, text:"Artificial way of causing rainfall to reduce air pollution makes use of", A:"Silver iodide and potassium iodide", B:"Silver nitrate and potassium iodide", C:"Silver iodide and potassium nitrate", D:"Silver nitrate and potassium chloride", ans:"A", category:"Science & Technology", subcategory:"Environmental Technology", tags:["Cloud Seeding","Artificial Rain"]},
{no:86, text:"Consider the following statements regarding the pardoning power of the President of India:\nI. Exercise of this power can be subjected to limited judicial review.\nII. The President can exercise this power without the advice of the Central Government.\nWhich statements are correct?", A:"I only", B:"II only", C:"Both I and II", D:"Neither I nor II", ans:"A", category:"Polity & Governance", subcategory:"President", tags:["Pardoning Power","Article 72"]},
{no:87, text:"Consider the following statements:\nI. After dissolution of the Lok Sabha, the Speaker continues in office until immediately before the first meeting of the next Lok Sabha.\nII. A Member elected as Speaker must resign from his/her political party.\nIII. The Speaker may be removed by a resolution passed by a majority of all the then members after at least fourteen days' notice.\nWhich statements are correct?", A:"I and II only", B:"II and III only", C:"I and III only", D:"I, II and III", ans:"C", category:"Polity & Governance", subcategory:"Parliament", tags:["Speaker of Lok Sabha"]},
{no:88, text:"Consider the following statements:\nI. Questions regarding disqualification under the Tenth Schedule are decided by the President in accordance with the advice of the Council of Ministers.\nII. The Constitution of India does not mention the term \"political party\".\nWhich statements are correct?", A:"I only", B:"II only", C:"Both I and II", D:"Neither I nor II", ans:"B", category:"Polity & Governance", subcategory:"Anti-Defection Law", tags:["Tenth Schedule","Anti-Defection Law"]},
{no:89, text:"Consider the following statements:\nStatement I: State Governments have no power to make rules for grant of concessions regarding extraction of minor minerals.\nStatement II: The Central Government has the power to notify minor minerals under the relevant law.\nWhich one is correct?", A:"Both I and II are correct and II explains I.", B:"Both I and II are correct but II does not explain I.", C:"Statement I is correct but Statement II is not correct.", D:"Statement I is not correct but Statement II is correct.", ans:"D", category:"Economy", subcategory:"Mining & Minerals", tags:["Minor Minerals","Mining Law"]},
{no:90, text:"Which organization enacted the Nature Restoration Law (NRL) to tackle climate change and biodiversity loss?", A:"European Union", B:"World Bank", C:"OECD", D:"FAO", ans:"A", category:"Environment & Ecology", subcategory:"International Environmental Law", tags:["Nature Restoration Law","European Union"]},
{no:91, text:"Consider the following statements:\nI. Panchayats at the intermediate level exist in all States.\nII. Minimum age to become a member of an intermediate Panchayat is 30 years.\nIII. The Chief Minister constitutes the State Finance Commission.\nWhich statements are not correct?", A:"I and II only", B:"II and III only", C:"I and III only", D:"I, II and III", ans:"D", category:"Polity & Governance", subcategory:"Local Self-Government", tags:["Panchayati Raj","73rd Amendment"]},
{no:92, text:"Consider the following statements regarding BIMSTEC:\nI. It consists of seven member States till January 2025.\nII. It came into existence with the Dhaka Declaration (1999).\nIII. Bangladesh, India, Sri Lanka, Thailand and Nepal are founding members.\nIV. Tourism sector in BIMSTEC is led by India.\nWhich statements are correct?", A:"I and II", B:"II and III", C:"I and IV", D:"I only", ans:"D", category:"International Relations", subcategory:"Regional Organizations", tags:["BIMSTEC"]},
{no:93, text:"Who among the following are members of the Jury to select the recipient of the 'Gandhi Peace Prize'?\nI. President of India\nII. Prime Minister of India\nIII. Chief Justice of India\nIV. Leader of Opposition in Lok Sabha", A:"II and IV only", B:"I, II and III", C:"II, III and IV", D:"I and III only", ans:"A", category:"Current Affairs", subcategory:"Awards & Honours", tags:["Gandhi Peace Prize"]},
{no:94, text:"GPS-Aided Geo Augmented Navigation (GAGAN) provides augmentation using ground stations. Which statements are correct?\nI. Provides additional accuracy and integrity.\nII. Enables more uniform and high-quality air traffic management.\nIII. Benefits only aviation and not other transport sectors.", A:"I, II and III", B:"II and III only", C:"I only", D:"I and II only", ans:"D", category:"Science & Technology", subcategory:"Space", tags:["GAGAN","Satellite Navigation"]},
{no:95, text:"Consider the following statements regarding the AI Action Summit held in Paris (February 2025):\nI. Co-chaired with India and built on the Bletchley Park (2023) and Seoul (2024) Summits.\nII. USA and UK signed the declaration on inclusive and sustainable AI.\nWhich statements are correct?", A:"I only", B:"II only", C:"Both I and II", D:"Neither I nor II", ans:"A", category:"Science & Technology", subcategory:"Artificial Intelligence", tags:["AI Action Summit","AI Governance"]},
{no:96, text:"Consider the following pairs:\nInternational Year — Year\nI. International Year of the Woman Farmer — 2026\nII. International Year of Sustainable and Resilient Tourism — 2027\nIII. International Year of Peace and Trust — 2025\nIV. International Year of Asteroid Awareness and Planetary Defence — 2029\nHow many pairs are correctly matched?", A:"Only one", B:"Only two", C:"Only three", D:"All the four", ans:"B", category:"Current Affairs", subcategory:"International Observances", tags:["International Years"]},
{no:97, text:"Consider the following statements regarding BRICS:\nI. The 16th BRICS Summit was held under Russia's chairmanship at Kazan.\nII. Indonesia has become a full member of BRICS.\nIII. Theme: \"Strengthening Multiculturalism for Just Global Development and Security.\"\nWhich statements are correct?", A:"I and II", B:"II and III", C:"I and III", D:"I only", ans:"D", category:"International Relations", subcategory:"Regional Organizations", tags:["BRICS"]},
{no:98, text:"Consider the following statements about Lokpal:\nI. Lokpal applies only to public servants in India, not those posted abroad.\nII. Only the Chief Justice of India can be Lokpal Chairperson.\nIII. Chairperson or Member must be at least 45 years old.\nIV. Lokpal cannot inquire into allegations against a sitting Prime Minister.\nWhich statements are correct?", A:"III only", B:"II and III", C:"I and IV", D:"None of the above", ans:"A", category:"Polity & Governance", subcategory:"Anti-Corruption Bodies", tags:["Lokpal"]},
{no:99, text:"Consider the following statements regarding the first Kho Kho World Cup:\nI. Held in Delhi, India.\nII. Indian men defeated Nepal 78–40 in the final.\nIII. Indian women defeated Nepal 54–36 in the final.\nWhich statements are correct?", A:"I only", B:"II and III only", C:"I and III only", D:"I, II and III", ans:"D", category:"Current Affairs", subcategory:"Sports", tags:["Kho Kho World Cup","Sports"]},
{no:100, text:"Consider the following statements:\nI. In the final of the 45th Chess Olympiad (2024), Gukesh Dommaraju became the world's youngest winner after defeating Ian Nepomniachtchi.\nII. Abhimanyu Mishra (USA) holds the record as the world's youngest Grandmaster.\nWhich statements are correct?", A:"I only", B:"II only", C:"Both I and II", D:"Neither I nor II", ans:"B", category:"Current Affairs", subcategory:"Sports", tags:["Chess Olympiad","Gukesh Dommaraju"]},
];
